SELECT * FROM CONTACTS_DEAL_IDS;

SELECT a.*, D.*, f.* FROM CONTACTS a
INNER JOIN CONTACTS_DEAL_IDS e
ON a.id = e.id
INNER JOIN DEALs D
ON e.value = D.id
INNER JOIN DEAL_HISTORY f
on D.id = f.deal_id
WHERE a.id = 31083230177;

SELECT * FROM CONTACTS_DEAL_IDS WHERE id = 31083230177;

